To wrap up our custom timer in a class:

```python
import ctypes
import multiprocessing as mp
from psychopy.core import getTime

class BlamTimer(object):
    def __init__(self):
        self.time = mp.Value('d', 0)
        self.poison_pill = mp.Value(ctypes.c_bool)
        self._proc = None
    def start(self):
        self.poison_pill = True
        self._proc = mp.Process(target=self.worker, args=(self.time, self.poison_pill))
        self._proc.start()
    def stop(self):
        self.poison_pill = False
    def now(self):
        return self.time.value
    def worker(self, time, pp):
        while pp.value:
            self.time.value = getTime()
```

